external_knowledge:
- "journey" metaphorically represents the solution process of each puzzle type;
- "AI adventurers" refers to the AI agents solving the puzzles;
- "conquer their challenges" implies solving the puzzles.

sql:
SELECT puzzles.puzzle_id, users.username
FROM puzzles
INNER JOIN users ON puzzles.creator_user_id = users.user_id;

SELECT ai_agent_id, COUNT(*) as total_puzzles_attempted
FROM attempts 
GROUP BY ai_agent_id;

SELECT puzzle_type_id, COUNT(*) as total_puzzles
FROM puzzles
GROUP BY puzzle_type_id;

SELECT ai_agent_id, puzzle_type_id, AVG(average_solution_time) AS avg_solution_time
FROM ai_performance
GROUP BY ai_agent_id, puzzle_type_id;

SELECT a.success, p.difficulty_level
FROM attempts a
INNER JOIN puzzles p ON a.puzzle_id = p.puzzle_id;
